const Q_BIOLOGY_1997=[{"id": "objective>Biology>1997>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled I is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Golgi body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mitochondrion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endoplasmic reticulum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vacuole</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The endoplasmic reticulum (ER) is a large, dynamic structure that serves many roles in the cell including calcium storage, protein synthesis and lipid metabolism. </div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1997>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Protein is synthesized in the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram provided, the part labeled for protein synthesis is typically the rough endoplasmic reticulum (RER), which is involved in protein synthesis due to the presence of ribosomes on its surface. <br/>  <br/> The rough endoplasmic reticulum (RER) is typically depicted as a series of connected, flattened sacs covered with ribosomes, often represented by small dots. <br/>  <br/> In this specific diagram, the rough endoplasmic reticulum appears to be the part labeled I, which fits the typical description and depiction of the rough endoplasmic reticulum.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1997>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the youngest plant tissue</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Meristem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Epidermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xylem</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Meristem is the youngest plant tissue. It is a type of plant tissue consisting of undifferentiated cells that can continue to divide and differentiate. Meristematic cells give rise to various tissues and organs of a plant and are responsible for growth. Phloem, epidermis, and xylem are differentiated tissues, which are typically older than meristematic tissue.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1997>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Viruses differ from all forms of life because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have thick cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feed on waste products of other organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">causes infectious diseases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">require other living cells to multiply</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viruses are different from all forms of life because they require other living cells to multiply. Viruses are considered non-living outside a host cell because they lack the ability to reproduce or carry out metabolic processes on their own. They need to infect a host cell and use the host's cellular machinery to replicate.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1997>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cnidoblast cells found in hydra are used for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offence and defence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">locomotion and nutrition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food collection</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cnidoblast cells found in hydra are used for offence and defence. Cnidoblasts, also known as cnidocytes, are specialized cells that contain a stinging organelle called a cnidocyst. These cells are used by the hydra to capture prey and for protection against predators.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1997>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Annelids differ from nematodes in that they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> exhibits bilateral symmetry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are triploblastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are metamerically segmented</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possess complete digestive system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Annelids differ from nematodes in that they are metamerically segmented. Metamerism is a type of body segmentation where the body is divided into repeating segments, each of which contains the same set of body structures. Annelids, such as earthworms, exhibit this type of segmentation, while nematodes, or roundworms, have a smooth, unsegmented body.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>1997>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following performs similar functions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Ascospores and ascocarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Antherozoids and rhizoids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sorus and indusium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Strobili and inflorescence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ascospores and ascocarp <br/> Ascospores: Sexual spores. <br/> Ascocarp: Fruiting body containing asci. <br/>   Related but different functions: spore production vs. spore housing. <br/> Antherozoids and rhizoids <br/> Antherozoids: Male gametes. <br/> Rhizoids: Root-like structures for anchorage and absorption. <br/>  Different functions: reproduction vs. support/nutrient absorption. <br/> Sorus and indusium <br/> Sorus: Cluster of sporangia. <br/> Indusium: Protective covering for sorus. <br/>   Related but different functions: spore production vs. protection. <br/> Strobili and inflorescence <br/> Strobili: Cone-like reproductive structures. <br/> Inflorescence: Cluster of flowers. <br/>   Similar functions: reproductive structures in different plant groups.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>1997>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In ferns, the sporophyte</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">develops from a haploid zygote</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduce asexually to produce spores</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> is haploid and dependant on gametophyte</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is diploid and independent of the gametophyte</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In ferns, the sporophyte is the diploid multicellular stage in the life cycle. It develops from a fertilized egg (zygote) and grows into a mature fern. It is independent of the gametophyte, the haploid multicellular stage, as it can photosynthesize and does not rely on the gametophyte for nutrients.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>1997>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group of insects that undergoes complete metamorphosis is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">houseflies, beetles and cockroaches</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cockroaches, grasshoppers and bees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">houseflies, beetles and butterflies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aphids, grasshopper and butterflies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Complete metamorphosis is a form of insect development which includes four life stages - egg, larva, pupa, and adult. Houseflies, beetles, and butterflies all undergo complete metamorphosis. <br/> A common acronym for insects that undergo complete metamorphosis (holometabolous insects) can be CHAF: <br/>  <br/> C: Coleoptera (beetles) <br/> H: Hymenoptera (ants, bees, wasps) <br/> A: Lepidoptera (butterflies, moths) <br/> F: Diptera (flies) <br/>  <br/> So, CHAF stands for Coleoptera, Hymenoptera, Lepidoptera, and Diptera. <br/>  <br/> For some common insects that undergo incomplete metamorphosis (hemimetabolous insects), use the acronym GOHB: <br/>  <br/> G: Gryllidae (crickets) <br/> O: Orthoptera (grasshoppers, locusts) <br/> H: Hemiptera (true bugs) <br/> B: Blattodea (cockroaches) <br/>  <br/> So, GOHB stands for Gryllidae, Orthoptera, Hemiptera, and Blattodea.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1997>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nitrogenous substance that is excreted by birds in order to conserve water is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitric acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds excrete uric acid as a nitrogenous waste product. This is because uric acid is less toxic and requires less water to excrete, which helps birds to conserve water. This is different from mammals, which excrete urea, and fish, which excrete ammonia.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>1997>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the exchange of nutrients and metabolic products occurs in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lymph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the exchange of nutrients and metabolic products occurs in the lymph. The lymphatic system is a network of tissues and organs that help rid the body of toxins, waste and other unwanted materials. The primary function of the lymphatic system is to transport lymph, a fluid containing infection-fighting white blood cells, throughout the body.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1997>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the stomach nearer the gullet is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">epiglottis</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> cardiac sphincter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duodenum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyloric sphincter</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the stomach nearer the gullet (esophagus) is called the cardiac sphincter. This is a circular muscle that prevents the acidic contents of the stomach from moving upwards into the esophagus.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1997>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trace elements are required by plants mainly for the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">formation of pigments and enzymes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of energy and hormones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufactured of carbohydrates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacture of proteins</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trace elements are required by plants mainly for the formation of pigments and enzymes. Trace elements are minerals that are needed in small amounts by plants for various physiological functions. Some trace elements are used to form pigments, which give plants their color, and enzymes, which are proteins that speed up chemical reactions in the plant's cells.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1997>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part that is similar to the bone is labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Enamel (I): The hard, outermost layer of the tooth, much harder than bone. <br/> Dentine (II): Lies beneath the enamel and is similar to bone in its composition and function. <br/> Pulp cavity (III): Contains nerves and blood vessels. <br/> Cementum (IV): Covers the tooth root and helps anchor it in place. <br/>  <br/> While enamel is the hardest substance in the body and provides the tooth with a protective outer layer, it is actually the dentine that is more similar to bone in terms of composition and function.  <br/>  <br/> Dentine and bone are both made of similar mineralized connective tissue and have comparable hardness and flexibility, whereas enamel is much harder and more brittle than bone. <br/>  <br/> So, the part that is most similar to bone is dentine (labeled II), not enamel. </div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1997>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled I and II constitute the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Crown</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neck</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The crown is the functional part of the tooth that is visible above the gum. In a mammalian tooth, the parts labeled I (enamel) and II (dentine) constitute the crown of the tooth. The crown is the visible part of the tooth above the gum line.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1997>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A food substance was treated with a few drops of Sudan III solution and a red coloration was obtained. The food contained</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral salt</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sudan III is a dye used in biology to stain lipids, triglycerides and lipoproteins on frozen paraffin sections. It has the appearance of reddish brown crystals. It is a lysochrome (fat-soluble dye) diazo dye used for the staining of lipids, triglycerides and lipoproteins in paraffin sections. The staining process involves the application of Sudan III on the substance, and if the substance contains lipids or fats, it will stain them red.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1997>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oozing out of water from the leaves of plants in a humid environment is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pinocytosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guttation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Guttation is the process of oozing out of water from the leaves of plants in a humid environment. It is a type of water secretion that occurs in certain plants, where they exude water from the tips or edges of their leaves. This usually happens during the night or early morning, when the soil is very moist and the transpiration rate is low. The water is pushed out from the leaf due to root pressure.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1997>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The element that is essential for the coagulation of blood is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The element that is essential for the coagulation of blood is calcium. Coagulation, also known as clotting, is the process by which blood changes from a liquid to a gel, forming a blood clot. It potentially results in hemostasis, the cessation of blood loss from a damaged vessel, followed by repair. The coagulation process is initiated by calcium ions (Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>).</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1997>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Anaerobic respiration differs from aerobic respiration by the production of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less amount of energy and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater amount of energy and alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less amount of energy and alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater amount of energy and water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anaerobic respiration differs from aerobic respiration by the production of less amount of energy and alcohol. Anaerobic respiration is a type of respiration that does not use oxygen. It is used when there is not enough oxygen for aerobic respiration. It produces less energy because the glucose is only partially broken down. Alcohol or lactic acid are often produced as byproducts.</div>", "topic": "RESPIRATION : ANAEROBIC RESPIRATION"}, {"id": "objective>Biology>1997>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stomatal pores open when there is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the sugar content of guard cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the osmotic concentration of the guard cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the sugar content of mesophyll cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the sugar content of mesophyll cells</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stomatal pores open when there is an increase in the sugar content of guard cells. The opening and closing of stomata are regulated by the water potential inside the guard cells. When the sugar content in the guard cells increases, it leads to an increase in osmotic potential causing water to move into the cells, making them turgid and causing the stomatal pore to open.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1997>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of deamination is essential for the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">digestion of protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> secretion of bile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of urea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of antibody</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deamination is the process by which amino groups from amino acids are removed. The amino group is converted into ammonia, which is toxic to the body and is converted into urea by the liver. The urea is then excreted in the urine. Therefore, the process of deamination is essential for the formation of urea.  <br/> (digestion of protein) would not be correct if a student chose that because deamination occurs after proteins have already been digested and absorbed as amino acids. Here's the distinction: <br/>  <br/> Digestion of protein: Involves breaking down proteins into amino acids, which occurs in the stomach and small intestine with the help of enzymes like pepsin and trypsin. <br/>  <br/> Deamination: Takes place in the liver after amino acids have been absorbed into the bloodstream. It involves removing the amino group from amino acids, resulting in ammonia, which is then converted into urea for excretion. <br/>  <br/> Thus, deamination is part of the process of nitrogen metabolism and waste removal (urea formation), not protein digestion.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>1997>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A band of connective tissue linking two bones in a joint is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tendon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cartilage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synovial membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ligament</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A band of connective tissue linking two bones in a joint is known as a ligament. Ligaments are strong, flexible tissues that hold bones together at the joints. They provide stability and limit the movement of joints to prevent dislocation. Tendons, on the other hand, connect muscles to bones, cartilage provides cushioning between bones, and the synovial membrane produces synovial fluid for lubrication in the joint.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1997>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The appendicular skeleton is composed of the pectoral girdle</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pelvic girdle, fore and hind limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pelvic girdle and fore limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbar vertebrae and pelvic girdle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbar vertebrae, fore and hind limbs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The appendicular skeleton is composed of the bones of the upper limbs (arms), the lower limbs (legs), and the girdles (pectoral and pelvic) that connect the limbs to the axial skeleton. Therefore, the appendicular skeleton is composed of the pectoral girdle, pelvic girdle, fore and hind limbs.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1997>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The companion cells are part of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pericycle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Companion cells are part of the phloem. The phloem is a tissue in vascular plants that transports nutrients from the leaves to the rest of the plant. Companion cells are specialized parenchyma cells, located in the phloem and connected to sieve elements. They assist in the transport and function of the sieve elements.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>1997>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following groups of vertebrates would the largest amount of yolk be found in the egg?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amphibians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reptiles</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The largest amount of yolk would be found in the eggs of reptiles. Yolk is a nutrient-rich substance in an egg that provides food for the developing embryo. Reptiles, such as turtles and lizards, lay eggs that have a large amount of yolk to nourish the embryo until it can hatch and find food on its own.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>1997>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The function of the part labelled V is for the passage of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pollen tube and pollen nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air, water and pollen nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air, antipodal cells and ovum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synergids and egg cell</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled V is the micropyle. It is an opening for the passage of air, water and pollen nucleus.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1997>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The female gamete is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The embryo sac contains the egg cell, which is the female gamete, the correct part representing the female gamete is the embryo sac.Therefore, the female gamete is represented by: III <br/>  <br/> The embryo sac, labeled III, houses the egg cell (female gamete) along with other cells involved in the fertilization process. The egg cell is the actual female gamete that, upon fertilization by a male gamete (sperm cell from pollen), will develop into a zygote and eventually form the seed.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>1997>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The type of vegetative reproduction illustrated in the diagram above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">grafting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adventitious bud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aerial layering</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The definition of adventitious buds is the formation of a plant organ in an unusual place. When plants normally produce new roots and shoots from buds, the production of these buds occurs from apical meristem tissues usually located at the base of stems.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>1997>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">coconut and oil palm fruits can be grouped as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">berry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capsule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drupe</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coconut and oil palm fruits can be grouped as drupes. A drupe is a type of fruit in which an outer fleshy part surrounds a shell (what we sometimes call a pit) with a seed inside. Examples of drupes include peaches, plums, and cherries—but also almonds, walnuts, and coconuts.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1997>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The substance that is responsible for optical dominance in plants is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gibberellin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tannin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">auxin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Auxin is the hormone responsible for phototropism in plants, which is the growth of organisms in response to a light stimulus. Phototropism is most often observed in plants, but can also occur in other organisms such as fungi. The cells on the plant that are farthest from the light have a higher concentration of auxin, which causes the cells to grow larger on the side of the plant furthest from the light, thus causing the plant to bend towards the light.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1997>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the brain that regulates most biological cycles in humans is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">olfactory lobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">optic lobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pineal body</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata is the bottom-most part of your brain. Its location means it's where your brain and spinal cord connect, making it a key conduit for nerve signals to and from your body. It also helps control vital processes like your heartbeat, breathing and blood pressure. <br/> The pineal body, also known as the pineal gland, plays a crucial role in regulating various biological cycles in humans, including: <br/>  <br/> - Circadian rhythms (sleep-wake cycles) <br/> - Hormone secretion (e.g., melatonin, serotonin) <br/> - Reproductive cycles (puberty, menstrual cycles) <br/> - Stress response <br/>  <br/> While the other options are brain regions with important functions, they aren't primarily responsible for regulating biological cycles: <br/>  <br/> Olfactory lobe: processes sensory information related to smell <br/> Optic lobe: involved in processing visual information <br/> Medulla oblongata: regulates autonomic functions like breathing, heart rate, and blood pressure</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1997>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of the eye to focus on both near and distant objects is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">image formation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypermetropia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accommodation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accommodation refers to the process by which the vertebrate eye changes optical power to maintain a clear image or focus on an object as its distance varies. In this process, the eye changes its focal length by changing the shape of its lens to focus on near or distant objects.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1997>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of wind can be measured with an instrument called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hygrometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secchi disc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anemometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind vane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of wind is measured using an instrument called an anemometer. An anemometer is a device used for measuring wind speed, and is a common weather station instrument. The term is derived from the Greek word anemos, meaning wind, and is used to describe any airspeed measurement instrument used in meteorology or aerodynamics.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>1997>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which organism in the food-web illustrated above is an omnivore? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Weevils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hawk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prayer mantis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An omnivore feeds on both flesh and plant,from the diagram the rat feeds on weevil(animal) and rice(plant).</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1997>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Toads and lizards in an ecosystem depend on a limited quantity of food. This is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intraspecific competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interspecific competition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The situation described in the question is an example of interspecific competition. Interspecific competition, in ecology, is a form of competition in which individuals of different species compete for the same resources in an ecosystem (e.g. food or living space). This can lead to a decrease in the population of less competitive species.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>1997>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive features of plants to desert conditions include?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thick barks, succulent stems and sunken stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> thin barks, succulent stems and sunken stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thin barks, air floats on stems and sunken stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air spaces in tissues, adventitious roots and thick barks</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adaptive features of plants to desert conditions include thick barks, succulent stems and sunken stomata. Thick barks help to reduce water loss, succulent stems store water, and sunken stomata (tiny openings in the leaf surface) reduce evaporation by being located below the leaf's surface.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1997>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Southern Guinea Savanna differs from the Northern Guinea Savanna in that it has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lower rainfall and shorter grasses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less grasses and scattered trees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more rainfall and taller grasses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less arboreal and burrowing animals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Southern Guinea Savanna differs from the Northern Guinea Savanna in that it has more rainfall and taller grasses. This is due to the fact that the Southern Guinea Savanna is closer to the equator and therefore receives more rainfall. The increased rainfall promotes the growth of taller grasses.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : GUINEA SAVANNA"}, {"id": "objective>Biology>1997>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">After a heavy rainfall and the formation of a large pond, the most likely sequence of changes in the vegetation of the pond is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Euglena → water lily → Spirogyra → grass</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> water lily → Spirogyra →grass → Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra → Euglena → grass → water lily</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Euglena → Spirogyra → water lily → grass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After a heavy rainfall and the formation of a large pond, the most likely sequence of changes in the vegetation of the pond is Euglena → Spirogyra → water lily → grass. This sequence represents a typical succession of pond vegetation, starting with unicellular organisms like Euglena, followed by filamentous algae like Spirogyra, then aquatic plants like water lilies, and finally terrestrial plants like grasses as the pond dries up.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>1997>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a soil sample, the relative amounts of the different soil particles can best be determined by the process of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">centrifugation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">precipitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sedimentation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a soil sample, the relative amounts of the different soil particles can best be determined by the process of sedimentation. This process involves settling out of particles from a suspension in a liquid.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>1997>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which is the most important pollutant of the marine environment in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Insecticides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sewage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inorganic fertilizers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important pollutant of the marine environment in Nigeria is oil. This is due to the high level of oil exploration and exploitation activities in the country, particularly in the Niger Delta region. Oil spills from these activities often find their way into the marine environment, causing significant pollution.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>1997>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the most effective ways of controlling guinea worm is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">treating the disease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public enlightenment campaigns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerating rural development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of portable drinking water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the most effective ways of controlling guinea worm is by the provision of portable drinking water. Guinea worm disease is caused by the parasite Dracunculus medinensis, which is transmitted through contaminated water. By providing clean, safe drinking water, the cycle of transmission can be broken, effectively controlling the disease.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1997>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During binary fission in lower organisms, the nucleus is known to undergo</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mitosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">meiosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fragmentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During binary fission in lower organisms, the nucleus is known to undergo mitosis. Binary fission is a type of asexual reproduction where an organism splits into two offspring. Before the organism splits, its DNA must be replicated. This replication is done through the process of mitosis, where the nucleus divides into two identical nuclei.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>1997>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One reason for the success of Mendel's work is that he</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">was the first to carry out research work on modern genetics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduced quantitative and qualitative elements into his work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selected two characteristics only at a time for study</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drew up his laws of inheritance based on his knowledge of chromosomes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mendel's success in his genetic experiments was largely due to his methodical approach and his choice of traits to study. He selected two characteristics at a time for study, which allowed him to observe the inheritance of individual traits, unencumbered by the effects of other traits. This approach is known as the law of independent assortment.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>1997>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The homozygous condition Hb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">s</span>Hb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">s</span>results in sickle cell anaemia whereas Hb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>Hb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">s</span> has the sickling trait. What is the probability that a couple with the sickling trait will give birth to one normal child?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">AA, AS, AS SS . so the probability is number of required outcome/ number of possible outcome. no of required outcome = 1 (AA)(normal). no of possible outcome =4 (AA, AS, AS, SS). 1÷4= 1/4.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>1997>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characters is NOT sex-linked?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">River blindness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Baldness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Haemophilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Colour blindness</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">River blindness is not a sex-linked trait. It is caused by a parasitic worm transmitted through the bite of a blackfly, not by inheritance of a particular gene. The other options (baldness, haemophilia, and colour blindness) are all examples of sex-linked traits, which are traits that are determined by genes located on the sex chromosomes.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>1997>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water loss is regulated in plants and animals by both the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scales and the skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scales and the hair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thick leaves and the feathers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leathery cuticle and the feathers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">leathery cuticle and the feathers help reduce water loss</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1997>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What combination of character should a prey develop to survive the environment of its predator?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Camouflage, well developed limbs and effective vision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Showy colour, big body and well developed limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Camouflage, big body and effective vision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Showy colour, well developed muscles and an acute sense of smell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To survive in an environment with predators, a prey animal needs to be able to hide (camouflage), escape quickly (well-developed limbs), and detect threats (effective vision). This combination of traits allows the animal to avoid detection, escape if detected, and be aware of its surroundings. Therefore, the correct answer is 'Camouflage, well developed limbs and effective vision'.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1997>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three classes in a termitarium are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soldiers, queen and workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers, soldiers and reproductives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soldiers, workers and kings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kings, queen and soldiers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A termitarium, or termite mound, is a complex structure that houses a termite colony. The colony is divided into three main classes or castes: workers, soldiers, and reproductives (which include the king and queen). Workers are responsible for foraging and building, soldiers defend the colony, and reproductives are responsible for reproduction. Therefore, the correct answer is 'workers, soldiers and reproductives'.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1997>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fossil records found in sedimentary rocks offer some explanation for the theory of evolution because <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the deposits have remains of organisms characteristic of when they were formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different strata have remains of organisms of the same kind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only organisms with strong parts are fossilized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">most animal and plant fossils bear little resemblance to present day living specimens</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fossil records found in sedimentary rocks do offer some explanation for the theory of evolution because the deposits have remains of organisms characteristic of when they were formed. This is because as organisms die, they get buried in sediment, which over time hardens into rock and preserves the remains of the organisms. These fossils provide a record of the history of life on Earth and can show how different species have evolved over time.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>1997>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Long neck in giraffe is used to illustrate the theory of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">use and disuse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">origin of species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">origin of life</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural selection</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Long neck in giraffe is used to illustrate the theory use and disuse of body parts</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}];
